const BOTH = ['host_client', 'server_sim'];
const HOST_ONLY = ['host_client'];
const core = (lane, serverSim = 'implemented', extra = {}) => ({
    capability: 'core',
    lane,
    serverSim,
    authorityModes: BOTH,
    ...extra,
});
const relay = (lane, serverSim = 'implemented', extra = {}) => ({
    capability: 'relay',
    lane,
    serverSim,
    authorityModes: BOTH,
    ...extra,
});
const ui = (serverSim = 'noop', extra = {}) => ({
    capability: 'ui',
    lane: 'client_local',
    serverSim,
    authorityModes: BOTH,
    ...extra,
});
const audio = (serverSim = 'noop', extra = {}) => ({
    capability: 'audio',
    lane: 'bridge',
    serverSim,
    authorityModes: BOTH,
    ...extra,
});
const ai = (lane, serverSim, extra = {}) => ({
    capability: 'ai',
    lane,
    serverSim,
    authorityModes: BOTH,
    ...extra,
});
const rtc = (serverSim = 'unsupported', extra = {}) => ({
    capability: 'rtc',
    lane: 'bridge',
    serverSim,
    authorityModes: HOST_ONLY,
    message: 'server_sim does not support realtime media/RTC ctx APIs. Use them only in client-local rendering or switch authorityMode.',
    ...extra,
});
const streaming = (serverSim = 'unsupported', extra = {}) => ({
    capability: 'streaming',
    lane: 'bridge',
    serverSim,
    authorityModes: HOST_ONLY,
    message: 'server_sim does not support streaming/STT ctx APIs yet. Use deterministic text/input state or switch authorityMode.',
    ...extra,
});
